kubectl patch statefulset mongodb-replica -n mongodb --type='json' -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/command",
    "value": ["mongod", "--config", "/etc/mongod/mongod.conf"]
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/volumeMounts",
    "value": [
      {"name": "data-volume", "mountPath": "/data/db"},
      {"name": "mongod-config-vol", "mountPath": "/etc/mongod"},
      {"name": "keyfile-vol", "mountPath": "/etc/mongo-keyfile", "readOnly": true}
    ]
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes",
    "value": [
      {
        "name": "mongod-config-vol",
        "configMap": {"name": "mongod-config"}
      },
      {
        "name": "keyfile-vol",
        "secret": {"secretName": "mongo-keyfile", "defaultMode": 256}
      }
    ]
  }
]' 2>&1
